resource "aws_codebuild_project" "example" {
  name          = "sample-codebuild-project"
  description   = "Sample project with secondary sources and artifacts"
  build_timeout = 60
  queued_timeout = 480
  concurrent_build_limit = 2

  service_role = aws_iam_role.codebuild_role.arn

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = true

    environment_variable {
      name  = "VAR1"
      value = "value1"
    }

    environment_variable {
      name  = "SECRET_VAR"
      value = "secure-value"
      type  = "PARAMETER_STORE"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/main-repo.git"
    git_clone_depth = 1
    buildspec = "buildspec.yml"
  }

  secondary_sources {
    type      = "GITHUB"
    location  = "https://github.com/example/secondary-repo-1.git"
    git_clone_depth = 2
    source_identifier = "secondary-source-1"
  }

  secondary_sources {
    type      = "BITBUCKET"
    location  = "https://bitbucket.org/example/secondary-repo-2.git"
    buildspec = "buildspec-secondary.yml"
    source_identifier = "secondary-source-2"
  }

  secondary_artifacts {
    type   = "S3"
    location = "my-output-bucket"
    name   = "artifact-1"
    packaging = "ZIP"
    path   = "output/artifacts"
    namespace_type = "BUILD_ID"
    override_artifact_name = true
    encryption_disabled = false
    artifact_identifier = "secondary-artifact-1"
  }

  secondary_artifacts {
    type   = "NO_ARTIFACTS"
    artifact_identifier = "secondary-artifact-2"
  }

  artifacts {
    type = "CODEPIPELINE"
  }

  cache {
    type = "S3"
    location = "my-codebuild-cache-bucket"
  }

  tags = {
    Environment = "Dev"
    Project     = "Sample"
  }
}

