resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  slot {
    slot_type           = "AMAZON.NUMBER"
    name                = "Quantity"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many pizzas would you like to order?"
        content_type = "PlainText"
      }
    }
    priority = 1
  }

  slot {
    slot_type           = "AMAZON.AlphaNumeric"
    name                = "CrustType"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of crust do you like? Thin, thick, or stuffed?"
        content_type = "PlainText"
      }
    }
    priority = 2
  }

  slot {
    slot_type           = "AMAZON.AlphaNumeric"
    name                = "Toppings"
    value_elicitation_prompt {
      max_attempts = 3
      message {
        content      = "What toppings would you like on your pizza? Like pepperoni, cheese, or veggies?"
        content_type = "PlainText"
      }
    }
    priority = 3
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
