        Action = [
          "cloudwatch:PutMetricData"
        ],
        Effect = "Allow",
        Resource = "*"
      }
    ]
  })
}

resource "aws_lambda_function" "pizza_order_handler" {
  filename      = "lambda_function_payload.zip"
  function_name = "PizzaOrderHandler"
  role          = aws_iam_role.lex_bot_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  environment {
    variables = {
      TABLE_NAME = aws_dynamodb_table.pizza_orders.name
    }
  }
}

resource "aws_dynamodb_table" "pizza_orders" {
  name           = "PizzaOrders"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "OrderId"

  attribute {
    name = "OrderId"
    type = "S"
  }
}

