  name                = "PizzaOrderBot"
  description         = "Bot to order pizza"
  child_directed      = false
  abort_statement {
    message {
      content          = "Sorry, I couldn't help with your pizza order."
      content_type     = "PlainText"
    }
  }

  intent {
    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  process_behavior = "BUILD"
  voice_id         = "Joanna"
  locale           = "en-US"
  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand. Would you like to order a pizza?"
      content_type = "PlainText"
    }
  }
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:invokeFunction"
  function_name = aws_lambda_function.pizza_order_handler.function_name
  principal     = "lex.amazonaws.com"
}
