resource "aws_kinesis_stream" "input_stream" {
  name        = "input-stream"
  shard_count = 1

  stream_mode_details {
    stream_mode = "PROVISIONED"
    scaling_configuration {
      scale_in_cooldown  = 300
      scale_out_cooldown = 300
    }
  }
}

resource "aws_kinesisanalyticsv2_application" "example" {
  name                     = "kinesis-analytics-app"
  runtime_environment      = "SQL-1_0"
  service_execution_role   = aws_iam_role.kinesis_role.arn

  application_configuration {
    application_code_configuration {
      code_content_type = "PLAINTEXT"
      code_content {
        text_content = "CREATE OR REPLACE STREAM "DESTINATION_STREAM" ("example_column" DOUBLE); INSERT INTO "DESTINATION_STREAM" SELECT STREAM "example_value" FROM "SOURCE_SQL_STREAM_001";"
      }
    }

    realtime_mode_configuration {}

    input {
      name_prefix = "SOURCE_SQL_STREAM"

      input_schema {
        record_format_type = "JSON"

        mapping_parameters {
          json_mapping_parameters {
            record_row_path = "$"
          }
        }

        record_column {
          name = "example_value"
          type = "DOUBLE"
        }
      }

      kinesis_streams_input {
        resource_arn = aws_kinesis_stream.input_stream.arn
        role_arn     = aws_iam_role.input_role.arn
      }
    }
  }
}

resource "aws_iam_role" "kinesis_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "kinesisanalytics.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role" "input_role" {
  name = "kinesis-input-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "kinesisanalytics.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "kinesis_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "kinesis:DescribeStream",
        "kinesis:GetRecords",
        "kinesis:GetShardIterator",
        "kinesis:ListStreams"
      ],
      "Resource": "${aws_kinesis_stream.input_stream.arn}"
    },
    {
      "Effect": "Allow",
      "Action": [
        "logs:PutLogEvents"
      ],
      "Resource": "arn:aws:logs:*:*:*"
    },
    {
      "Effect": "Allow",
      "Action": [
        "cloudwatch:PutMetricData"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "input_policy" {
  name = "kinesis-input-policy"
  role = aws_iam_role.input_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "kinesis:DescribeStream",
        "kinesis:GetRecords",
        "kinesis:GetShardIterator",
        "kinesis:ListStreams"
      ],
      "Resource": "${aws_kinesis_stream.input_stream.arn}"
    }
  ]
}
EOF
}

