resource "aws_kinesis_firehose_delivery_stream" "to_http_endpoint" {
  name        = "firehose-to-http-endpoint"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url = "https://firehose.nr-data.net/v1/firehose/kinesis"
    name = "NewRelicEndpoint"

    access_key = "YOUR_NEW_RELIC_INSERT_KEY"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.bucket.arn

      # Buffer incoming data for up to 5 minutes or until 10 MiB, whichever comes first
      buffer_size  = 10
      buffer_interval = 300

      compression_format = "GZIP"
    }

    # Mapping to transform data using processor
    processing_configuration {
      processor {
        type = "RecordDeAggregation"

        parameters {
          parameter_name  = "SubRecordType"
          parameter_value = "json"
        }
      }

      processor {
        type = "AppendDelimiterToRecord"
      }

      processor {
        type = "MetadataExtraction"

        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "$.metadata"
        }

        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.0"
        }
      }
    }

    # Optional: Endpoint retry configuration
    retry_duration = 300
  }
}

resource "aws_s3_bucket" "bucket" {
  bucket = "firehose-http-endpoint-bucket"
}

resource "aws_iam_role" "firehose_role" {
