resource "aws_kendra_data_source" "example" {
  index_id = aws_kendra_index.example.id
  name     = "example-data-source"
  type     = "S3"

  configuration {
    s3_configuration {
      bucket_name = "example-s3-bucket"

      access_control_list_configuration {
        key = "s3/acl"
      }

      document_content_deployment_mode = "DIRECT"
      inclusion_prefixes               = ["example-prefix-1", "example-prefix-2"]
      exclusion_patterns               = ["example-pattern-1", "example-pattern-2"]

      proxy_configuration {
        host               = "proxy-server.example.com"
        port               = 8080
        credentials        = "arn:aws:secretsmanager:us-west-2:123456789012:secret:ProxyCredentials"
        protocol           = "HTTP"
      }
    }
  }

  depends_on = [aws_iam_role_policy.kendra_policy]
}

resource "aws_iam_role" "kendra_role" {
  name = "KendraDataSourceRole-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_policy" {
  name = "KendraDataSourcePolicy-${random_id.suffix.hex}"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::example-s3-bucket",
          "arn:aws:s3:::example-s3-bucket/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = "arn:aws:secretsmanager:us-west-2:123456789012:secret:ProxyCredentials"
      }
    ]
  })
}
```

