resource "aws_kendra_data_source" "example" {
  index_id = "12345678-1234-1234-1234-123456789012"
  name     = "example-data-source"
  type     = "WEBCRAWLER"

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = [
            "https://example.com"
          ]
          web_crawl_mode = "SUBDOMAINS"
        }
      }

      crawl_depth                = 2
      max_content_size_in_mega_bytes = 50
      max_urls_per_minute_crawl_rate = 300

