resource "null_resource" "patch_coredns" {
  provisioner "local-exec" {
    command = <<EOT
      export KUBECONFIG=./kubeconfig
      cat <<EOF | kubectl apply -f -
      apiVersion: v1
      kind: ConfigMap
      metadata:
        name: coredns
        namespace: kube-system
      data:
        Corefile: |
          .:53 {
              errors
              health
              kubernetes cluster.local in-addr.arpa ip6.arpa {
                pods insecure
                upstream
                fallthrough in-addr.arpa ip6.arpa
              }
              prometheus :9153
              forward . /etc/resolv.conf
              cache 30
              loop
              reload
              loadbalance
          }
      EOF

      kubectl patch deployment coredns \n        -n kube-system \n        --type strategic \n        --patch='{"spec": {"template": {"spec": {"serviceAccountName": "fargate"}}}}'
    EOT

    environment = {
      AWS_EKS_ENDPOINT                   = aws_eks_cluster.example.endpoint
      AWS_EKS_CERTIFICATE_AUTHORITY    = aws_eks_cluster.example.certificate_authority[0].data
      AWS_EKS_AUTH_TOKEN               = data.aws_eks_cluster_auth.example.token
    }
  }

  triggers = {
    cluster_endpoint = aws_eks_cluster.example.endpoint
    core_dns_patched = "true"
  }
}

