data "aws_ssm_parameter" "amzn2_ami_latest" {
  name = "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2"
}

resource "aws_ami" "from_latest_amzn2" {
  name               = "custom-amzn2-with-cpu-options"
  source_ami_id      = data.aws_ssm_parameter.amzn2_ami_latest.value
  virtualization_type = "hvm"
  root_device_name   = "/dev/xvda"

  # Copy the EBS block device mapping from the source AMI
  dynamic "ebs_block_device" {
    for_each = [for bd in jsondecode(data.aws_ssm_parameter.amzn2_ami_latest.value).block_device_mappings : bd if bd.device_name == "/dev/xvda"]
    content {
      device_name = ebs_block_device.value.device_name
      snapshot_id = ebs_block_device.value.ebs.snapshot_id
      volume_size = ebs_block_device.value.ebs.volume_size
      volume_type = ebs_block_device.value.ebs.volume_type
      encrypted   = ebs_block_device.value.ebs.encrypted
    }
  }
}

# Note: CPU options like vCPUs and threads per core are set at the instance level, not the AMI level.
# To use 2 vCPUs and 2 threads per core, launch an instance with an instance type that supports this configuration.
# Example instance using the created AMI:
resource "aws_instance" "example" {
  ami           = aws_ami.from_latest_amzn2.id
  instance_type = "t3.small" # Example: 2 vCPUs, supports 2 threads per core (default for Intel)

  # CPU options (only effective on supported instance types)
  cpu_options {
    core_count       = 1
    threads_per_core = 2
  }
}
