    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_efs_file_system" "shared" {
  tags = {
    Name = "shared-efs"
  }
}

resource "aws_efs_mount_target" "private" {
  count             = 2
  file_system_id    = aws_efs_file_system.shared.id
  subnet_id         = aws_subnet.private[count.index].id
  security_groups   = [aws_security_group.allow_efs.id]
}

data "aws_ssm_parameter" "amzn2_latest" {
  name = "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2"
}

resource "aws_instance" "private_ec2" {
  count                  = 2
  ami                    = data.aws_ssm_parameter.amzn2_latest.value
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.allow_efs.id]
  associate_public_ip_address = false

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils nfs-utils
              mkdir -p /mnt/efs
              echo "${aws_efs_file_system.shared.dns_name}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              mount -a
              EOF

  tags = {
    Name = "private-ec2-${count.index}"
  }
}
```

