  database_name             = "mydb"
  master_username           = "adminuser"
  master_password           = random_password.password.result
  node_type                 = "dc2.large"
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  publicly_accessible       = false
  skip_final_snapshot       = true

  # Optional: specify VPC security group and subnet group if needed
  # vpc_security_group_ids  = [aws_security_group.redshift-sg.id]
  # cluster_subnet_group_name = aws_redshift_subnet_group.example.name
}

resource "random_password" "password" {
  length  = 16
  special = true
  override_special = "!@#$%^&*"
}

resource "aws_redshift_cluster_iam_roles" "example" {
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  iam_role_arns      = [aws_iam_role.example.arn]
}

resource "aws_iam_role" "example" {
  name = "redshift-iam-role-${random_id.cluster_id.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "example" {
  name = "redshift-resource-policy-${random_id.cluster_id.hex}"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::mybucket",
          "arn:aws:s3:::mybucket/*"
        ]
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "example" {
  name       = "redshift-policy-attachment-${random_id.cluster_id.hex}"
  roles      = [aws_iam_role.example.name]
  policy_arn = aws_iam_policy.example.arn
}
```

