data "aws_sagemaker_prebuilt_ecr_image" "kmeans" {
  repository_name = "sagemaker-kmeans"
}

resource "aws_s3_bucket" "model_bucket" {
  bucket = "sagemaker-model-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_object" "model_artifacts" {
  bucket = aws_s3_bucket.model_bucket.id
  key    = "model.tar.gz"
  source = "path/to/your/model.tar.gz"
}

resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })

  inline_policy {
    name = "sagemaker-policy"

    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Action = [
            "s3:GetObject",
            "s3:PutObject"
          ]
          Resource = aws_s3_object.model_artifacts.arn
        },
        {
          Effect = "Allow"
          Action = [
            "ecr:BatchCheckLayerAvailability",
            "ecr:GetDownloadUrlForLayer",
            "ecr:BatchGetImage"
          ]
          Resource = data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_id
        },
        {
          Effect = "Allow"
          Action = "ecr:GetAuthorizationToken"
          Resource = "*"
        }
      ]
    })
  }
}

resource "aws_sagemaker_model" "kmeans_model" {
  name               = "kmeans-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    image = data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_path
    model_data_url = "s3://${aws_s3_bucket.model_bucket.id}/${aws_s3_object.model_artifacts.key}"
  }
}

