    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })

  inline_policy {
    name = "sagemaker-policy"

    policy = jsonencode({
      Version = "2012-10-17"
