    ]
    security_groups = [aws_security_group.msk_security_group.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn
  }

  client_authentication {
    sasl {
      iam = true
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  logging_info {
    broker_logs {
      s3 {
        enabled          = true
        bucket           = aws_s3_bucket.msk_logs.id
        prefix           = "logs/"
        kms_key_id       = aws_kms_key.s3_kms_key.arn
      }
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      firehose {
        enabled = false
      }
    }
  }

  tags = {
    Environment = "test"
  }
}

