  name        = "example-cluster-configuration"
  description = "Example MSK cluster configuration"
  kafka_versions = ["2.8.1"]

  server_properties = <<PROPERTIES
auto.create.topics.enable = true
delete.topic.enable = true
PROPERTIES
}

