resource "random_id" "cluster_suffix" {
  byte_length = 4
}

resource "aws_kms_key" "msk_encryption" {
  description = "KMS key for Amazon MSK encryption at rest"
  enable_key_rotation = true
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-cluster-logs-${random_id.cluster_suffix.hex}"
  retention_in_days = 7
}

resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket-${random_id.cluster_suffix.dec}"
  force_destroy = true
}

resource "aws_kinesis_firehose_delivery_stream" "msk_logs_stream" {
  name        = "msk-logs-firehose-${random_id.cluster_suffix.hex}"
  destination = "s3"

  s3_configuration {
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
    role_arn   = aws_iam_role.firehose_role.arn
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose-msk-logs-role-${random_id.cluster_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ]
        Effect = "Allow"
        Resource = "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      }
    ]
  })
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster-${random_id.cluster_suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.subnet1.id,
      aws_subnet.subnet2.id,
      aws_subnet.subnet3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    ebs_volume_size = 100
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {}
      node_exporter {}
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.id
        prefix  = "msk-logs/"
      }
    }
  }
}

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

resource "aws_subnet" "subnet3" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"

  tags = {
    Name = "msk-subnet-3"
  }
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-cluster-sg"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

