resource "random_password" "cluster" {
  length  = 16
  special = true
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier           = "mysql-cluster-${random_password.cluster.result}"
  engine                       = "aurora-mysql"
  master_username              = "admin"
  master_password              = random_password.cluster.result
  db_cluster_parameter_group_name = "default.aurora-mysql5.7"
  backup_retention_period      = 5
  preferred_backup_window      = "07:00-09:00"
  apply_immediately            = true
  skip_final_snapshot          = true
  storage_encrypted            = true
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  for_each              = data.aws_availability_zones.available.names
  identifier            = "mysql-cluster-instance-${each.value}"
  cluster_identifier    = aws_rds_cluster.mysql_cluster.id
  instance_class        = "db.r5.large"
  engine                = "aurora-mysql"
  db_subnet_group_name  = aws_db_subnet_group.subnet_group.name
  availability_zone     = each.value

  // Allocate 100 GB per instance in each availability zone
  allocated_storage     = 100
}

resource "aws_db_subnet_group" "subnet_group" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = aws_subnet.private[*].id
  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "MySQL Cluster VPC"
  }
}

resource "aws_subnet" "private" {
  for_each = data.aws_availability_zones.available.names
  vpc_id               = aws_vpc.main.id
  cidr_block           = cidrsubnet(aws_vpc.main.cidr_block, 8, index(data.aws_availability_zones.available.names, each.value))
  availability_zone    = each.value
  map_public_ip_on_launch = false

  tags = {
    Name = "MySQL Subnet - ${each.value}"
  }
}

