  name       = "neptune-subnet-group-${random_id.cluster_suffix.hex}"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

resource "aws_security_group" "neptune_sg" {
  vpc_id = aws_vpc.example.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24", "10.0.2.0/24"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

resource "aws_neptune_cluster" "example" {
  cluster_identifier                   = "neptune-cluster-${random_id.cluster_suffix.hex}"
  engine                               = "neptune"
  neptune_subnet_group_name            = aws_db_subnet_group.neptune_subnets.name
  vpc_security_group_ids               = [aws_security_group.neptune_sg.id]
  neptune_parameter_group_name         = aws_neptune_parameter_group.example.name
  skip_final_snapshot                  = true
  backup_retention_period              = 5
  preferred_backup_window              = "07:00-09:00"
  preferred_maintenance_window         = "sat:04:00-sat:05:00"
  enable_cloudwatch_logs_exports       = ["audit"]
}
