resource "aws_s3_bucket" "autograding_artifacts" {
  bucket = "autograding-artifacts-${random_password.github_token.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle_rule {
    enabled = true
    expiration {
      days = 30
    }
  }
}

resource "aws_codebuild_project" "autograding" {
  name          = "autograding-project"
  description   = "Auto-grading system for CS course submissions"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/exampleorg/student-submission-repo"
    git_clone_depth = 1

    auth {
      type  = "OAUTH"
      resource = aws_secretsmanager_secret_version.github_oauth_token.arn
    }
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "STUDENT_REPO"
      value = "true"
    }

    environment_variable {
      name  = "GRADESCOPE_API_URL"
      value = "https://gradescope.com/api/v1"
      type  = "PLAINTEXT"
    }
  }

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.bucket
    path = "grades"
    package_zip = false
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograding"
      stream_name = "autograding-stream"
    }

    s3_logs {
      enabled = true
      location = "${aws_s3_bucket.autograding_artifacts.bucket}/logs"
    }
  }

  cache {
    type = "S3"
    location = "${aws_s3_bucket.autograding_artifacts.bucket}/cache"
  }

  tags = {
    Project = "AutoGrading"
    Course  = "CS101"
  }
}

resource "aws_secretsmanager_secret" "github_oauth_token" {
  name = "github/oauth-token"
}

resource "aws_secretsmanager_secret_version" "github_oauth_token" {
  secret_id     = aws_secretsmanager_secret.github_oauth_token.id
  secret_string = "ghp_XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX"
}

resource "aws_cloudwatch_event_rule" "github_webhook" {
  name        = "codebuild-github-webhook"
  description = "Trigger CodeBuild on GitHub push"

  event_pattern = jsonencode({
    source = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      "project-name": [aws_codebuild_project.autograding.name]
      "build-status": ["SUCCEEDED", "FAILED"]
    }
  })
}

resource "aws_cloudwatch_event_target" "codebuild_target" {
  rule      = aws_cloudwatch_event_rule.github_webhook.name
  target_id = "autograding-build"
  arn       = aws_codebuild_project.autograding.arn
}

