      name  = "GITHUB_REPO"
      value = "student-submission-repo"
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-org/student-submissions.git"
    git_clone_depth = 1
    report_build_status = true
  }

  source_version = "main"

  logs_config {
