    location = aws_s3_bucket.grading_artifacts.bucket
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    privileged_mode = true

    environment_variable {
      name  = "ARTIFACT_BUCKET"
      value = aws_s3_bucket.grading_artifacts.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "student-submission-repo"
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-org/student-submissions.git"
    git_clone_depth = 1
    report_build_status = true
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograding"
      stream_name = "main"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_artifacts.bucket}/logs"
    }
  }

  tags = [
    {
      key   = "Project"
      value = "CS-Course-Autograding"
    }
  ]
}

resource "aws_cloudwatch_event_rule" "github_push_trigger" {
  name        = "github-push-autograding-trigger"
  description = "Trigger autograding build on GitHub push"
  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      "build-status" = ["SUCCEEDED", "FAILED"]
    }
  })
}

resource "aws_cloudwatch_event_target" "codebuild_target" {
  rule      = aws_cloudwatch_event_rule.github_push_trigger.name
  target_id = "autograding-build-complete"
  arn       = aws_codebuild_project.autograding_project.arn
}

resource "aws_sns_topic" "grading_notification_topic" {
  name = "cs-autograding-notifications"
}

resource "aws_sns_topic_subscription" "student_email_sub" {
  topic_arn = aws_sns_topic.grading_notification_topic.arn
  protocol  = "email"
  endpoint  = "student@example.com"
}

resource "aws_cloudwatch_log_group" "autograding_logs" {
  name = "/aws/codebuild/cs-autograding"
  retention_in_days = 7
}
