resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_vpc" "codebuild_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "codebuild-no-internet-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.codebuild_vpc.id

  tags = {
    Name = "no-internet-igw"
  }
}

# Ensure no route to internet by not adding a default route to the IGW
resource "aws_subnet" "codebuild_subnet" {
  vpc_id                  = aws_vpc.codebuild_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "codebuild-subnet-${random_id.suffix.hex}"
  }
}

resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.codebuild_vpc.id

  tags = {
    Name = "private-route-table-no-internet"
  }
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.codebuild_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# No route to 0.0.0.0/0 added — this ensures no internet access

resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-security-group-${random_id.suffix.hex}"
  description = "Security group for CodeBuild with no internet access"
  vpc_id      = aws_vpc.codebuild_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/8"] # Allow egress only within VPC
  }

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/8"] # Allow ingress only from within VPC
  }

  tags = {
    Name = "codebuild-sg-no-outbound"
  }
}

resource "aws_codebuild_project" "autograding_project" {
  name         = "autograding-project-${random_id.suffix.hex}"
  description  = "Autograding system for CS course - runs student code with no internet access"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/user/course-submissions.git"
    git_clone_depth = 1

    git_clone_depth_type = "SHALLOW"
    buildspec = <<EOT
version: 0.2
phases:
  pre_build:
    commands:
      - echo "Setting up test environment"
      - apt-get update -y
      - apt-get install -y python3 python3-pip
  build:
    commands:
      - echo "Running student code and tests"
      - chmod +x ./run_tests.sh
      - ./run_tests.sh
  post_build:
    commands:
      - echo "Uploading results"
      - aws s3 cp results.txt s3://course-autograding-results/${random_id.suffix.hex}/results.txt
artifacts:
  files:
    - results.txt
EOT
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "SUBMISSION_ID"
      value = random_id.suffix.hex
    }
  }

  vpc_config {
    vpc_id                  = aws_vpc.codebuild_vpc.id
    subnets                 = [aws_subnet.codebuild_subnet.id]
    security_group_ids      = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograding-logs"
      stream_name = "build"
    }
    s3_logs {
      location = "course-autograding-logs-${random_id.suffix.hex}/build.log"
      encrypted = true
    }
  }

  tags = [
    {
      key   = "Project"
      value = "AutogradingSystem"
    },
    {
      key   = "Course"
      value = "CS101"
    }
  ]
}

resource "aws_s3_bucket" "grading_results" {
  bucket        = "course-autograding-results-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_iam_role" "codebuild_role" {
