  description  = "Autograder for CS course student submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifact_bucket.bucket
    package_zip = true
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.artifact_bucket.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token
      type  = "PLAINTEXT"
    }

    privileged_mode = false
  }

  source {
    type      = "GITHUB"
    git_clone_depth = 1
    location  = "https://github.com/example-org/cs-course-labs.git"
    buildspec = "buildspec.yml"
  }

  vpc_config {
    vpc_id = aws_vpc.grading_vpc.id
    subnets = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Project = "CS-Autograder"
  }

  # Disable public internet access in the VPC subnets and security group
  # Ensures student code cannot access the internet during execution
}

resource "aws_cloudwatch_log_group" "autograder_logs" {
  name = "/aws/codebuild/${aws_codebuild_project.autograder.name}"
  retention_in_days = 7
}

# Input variable for GitHub token (should be passed securely)
variable "github_token" {
  description = "GitHub personal access token for cloning private student repos"
  type        = string
  sensitive   = true
}
