    description      = "Allow HTTP from VPC"
    protocol         = "tcp"
    from_port        = 80
    to_port          = 80
    cidr_blocks      = [aws_vpc.main.cidr_block]
  }

  egress {
    description      = "Allow HTTP outbound to any"
    protocol         = "tcp"
    from_port        = 80
    to_port          = 80
    cidr_blocks      = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg-${random_id.vpc_suffix.hex}"
  }
}

resource "aws_lb" "app_lb" {
  name               = "app-lb-${random_id.vpc_suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.subnet1.id, aws_subnet.subnet2.id, aws_subnet.subnet3.id]

  tags = {
    Name = "app-lb-${random_id.vpc_suffix.hex}"
  }
}

resource "aws_lb_target_group" "tg" {
  name     = "target-group-${random_id.vpc_suffix.hex}"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    path                = "/"
    protocol            = "HTTP"
    timeout             = 5
    healthy_threshold   = 5
    unhealthy_threshold = 2
    interval            = 30
  }

  tags = {
    Name = "target-group-${random_id.vpc_suffix.hex}"
  }
}

resource "aws_lb_listener" "http_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["099720109477"] # Canonical

  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }
}

resource "aws_instance" "web_server" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet1.id
  vpc_security_group_ids = [aws_security_group.alb_sg.id]

  tags = {
    Name = "web-server-${random_id.vpc_suffix.hex}"
  }
}

resource "aws_lb_target_group_attachment" "attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  target_id        = aws_instance.web_server.id
  port             = 80
}

resource "aws_route53_zone" "main" {
  name = "test-video-stream.com"
}

resource "aws_route53_record" "lb_alias_ipv4" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "lb_alias_ipv6" {
