resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "db" {
  length  = 16
  special = true
}

resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 7
}

resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-example-vpc"
  }
}

resource "aws_subnet" "example" {
  count = 2

  vpc_id            = aws_vpc.example.id
  cidr_block        = cidrsubnet(aws_vpc.example.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "rds-example-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "example" {
  name       = "rds-subnet-group-${random_id.suffix.hex}"
  subnet_ids = aws_subnet[*].id

  tags = {
    Name = "rds-subnet-group"
  }
}

resource "aws_security_group" "rds" {
  name        = "rds-security-group-${random_id.suffix.hex}"
  description = "Allow PostgreSQL access from specific sources"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

resource "aws_db_parameter_group" "postgres" {
  name        = "custom-postgres-${random_id.suffix.hex}"
  family      = "postgres14"
  description = "Custom parameter group for PostgreSQL"

  parameter {
    name  = "log_statement"
    value = "all"
  }
}

resource "aws_db_instance" "example" {
  identifier                  = "postgres-db-${random_id.suffix.hex}"
  engine                      = "postgres"
  engine_version              = "14.7"
  instance_class              = "db.t3.micro"
  allocated_storage           = 20
  storage_type                = "gp2"
  db_name                     = "mydb"
  username                    = "postgresadmin"
  password                    = random_password.db.result
  db_subnet_group_name        = aws_db_subnet_group.example.name
  vpc_security_group_ids      = [aws_security_group.rds.id]
  parameter_group_name        = aws_db_parameter_group.postgres.name
  multi_az                    = true
  backup_retention_period     = 7
  encrypted                   = true
  kms_key_id                  = aws_kms_key.rds.arn
  skip_final_snapshot         = true
  apply_immediately           = false
  auto_minor_version_upgrade  = true
  publicly_accessible         = false
  allow_major_version_upgrade = false
}
```

