  tags = {
    Name = "aurora-subnet-group"
  }
}

resource "aws_secretsmanager_secret" "aurora_secret" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "aurora_secret_version" {
