  idle_client_timeout      = 1800
  require_tls              = false
  debug_logging            = false
  tags = {
    Environment = "production"
  }
}

resource "aws_db_proxy_default_target_group" "proxy_default_target" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  connection_pool_config {
