resource "aws_lightsail_instance" "mysql_instance" {
  name              = "mysql-instance-${random_id.suffix.hex}"
  availability_zone = "us-west-2a"
  blueprint_id      = "ubuntu_20_04" # Using Ubuntu as base OS; can be changed to Amazon Linux if needed
  bundle_id         = "nano_2_0"

  user_data = <<-EOF
              #!/bin/bash
              apt-get update
              apt-get install -y mysql-server
              systemctl start mysql
              systemctl enable mysql

              # Secure MySQL installation and set root password
              mysql -e "ALTER USER 'root'@'localhost' IDENTIFIED WITH mysql_native_password BY '${random_password.db_password.result}';"
              mysql -e "DELETE FROM mysql.user WHERE User='';"
              mysql -e "DELETE FROM mysql.user WHERE User='root' AND Host NOT IN ('localhost', '127.0.0.1', '::1');"
              mysql -e "DROP DATABASE IF EXISTS test;"
              mysql -e "DELETE FROM mysql.db WHERE Db='test' OR Db='test\_%';"
              mysql -e "FLUSH PRIVILEGES;"
              EOF
}

output "instance_private_ip" {
  value = aws_lightsail_instance.mysql_instance.private_ip_address
}

output "mysql_root_password" {
  value     = random_password.db_password.result
  sensitive = true
}

