  role       = aws_iam_role.dlm_role.name
}

resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description        = "Apply Glacier vault lock"
  execution_role_arn = aws_iam_role.dlm_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Glacier-backup-schedule"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
      }

      retain_rule {
        count = 10
      }

      # Using archive_rule to move snapshots to Glacier
      archive_rule {
        retain_rule {
          # Retain archived snapshots for 7 years
          retention_days = 2555
        }
      }
    }

    # Target tags to identify resources
    tag_filter {
      key    = "backup"
      values = ["true"]
    }
  }
}

