  name        = "instance-security-group"
  description = "Allow traffic from LB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    security_group_id = aws_security_group.lb_sg.id
  }

